#[test]
fn ssh_policy_full() {
    // Hand-constructed using Rust's PascalCase JSON keys (NOT Go-generated).
    // Go's SSH types use camelCase json tags ("rules", "principals",
    // "sshUsers", "action", etc.) but rustscale uses PascalCase without
    // serde rename. See bug #3 in module docs.
    let json = include_str!("../fixtures/ssh_policy_full.json");
    assert_json_roundtrip::<rustscale_tailcfg::SSHPolicy>(json);
}

