// ─── Binary fixture tests (DERP frame) ───

#[test]
fn derp_frame() {
    let bin = include_bytes!("../fixtures/derp_frame.bin");
    // A DERP frame is: 1-byte type + 4-byte BE length + payload.
    let header_len = rustscale_derp::FRAME_HEADER_LEN;
    assert!(bin.len() >= header_len, "derp_frame.bin too short");

    let mut header = [0u8; 5];
    header.copy_from_slice(&bin[..header_len]);
    let (typ, len) = rustscale_derp::decode_frame_header(&header);
    assert_eq!(
        len as usize + header_len,
        bin.len(),
        "declared length matches file"
    );

    // Re-encode the header.
    let re_encoded_header = rustscale_derp::encode_frame_header(typ, len);
    assert_binary_roundtrip(&header, &re_encoded_header);

    // Full frame: header + payload.
    let mut re_encoded = re_encoded_header.to_vec();
    re_encoded.extend_from_slice(&bin[header_len..]);
    assert_binary_roundtrip(bin, &re_encoded);
}

// ─── Binary fixture tests (STUN) ───

#[test]
fn stun_binding_response() {
    let bin = include_bytes!("../fixtures/stun_binding_response.bin");
    let (tx_id, addr) =
        rustscale_netcheck::parse_response(bin).expect("parse stun_binding_response");
    let re_encoded = rustscale_netcheck::response(&tx_id, addr);
    assert_binary_roundtrip(bin, &re_encoded);
}
